code = """import json
import pandas as pd

# Load data from both databases
books_file = locals()['var_functions.query_db:12']
reviews_file = locals()['var_functions.query_db:24']

# Read data
df_books = pd.read_json(books_file)
df_reviews = pd.read_json(reviews_file)

print("=== DATA OVERVIEW ===")
print(f"Total books: {len(df_books)}")
print(f"Total reviews: {len(df_reviews)}")

# Extract numeric IDs
print("\n=== SAMPLE BOOK IDs ===")
print(df_books['book_id'].head(10).tolist())

print("\n=== SAMPLE REVIEW purchase_ids ===")
print(df_reviews['purchase_id'].head(10).tolist())

# Let's see if there are any purchase_ids that start with 'bookid'
print("\n=== Looking for bookid pattern in purchase_ids ===")
bookid_reviews = df_reviews[df_reviews['purchase_id'].str.contains('bookid', na=False)]
print(f"Found {len(bookid_reviews)} reviews with 'bookid' in purchase_id")

if len(bookid_reviews) > 0:
    print("Sample:", bookid_reviews['purchase_id'].head().tolist())

# Let's see if there are any book_ids that start with 'purchaseid'
print("\n=== Looking for purchaseid pattern in book_ids ===")
purchaseid_books = df_books[df_books['book_id'].str.contains('purchaseid', na=False)]
print(f"Found {len(purchaseid_books)} books with 'purchaseid' in book_id")

if len(purchaseid_books) > 0:
    print("Sample:", purchaseid_books['book_id'].head().tolist())

print('__RESULT__:')
print(json.dumps({
    'status': 'data loaded',
    'books_count': len(df_books),
    'reviews_count': len(df_reviews)
}))"""

